-- StarterPlayer/StarterPlayerScripts/CombatFeel.client.lua
W({'StarterPlayer','StarterPlayerScripts','CombatFeel'}, 'LocalScript', [[
-- CombatFeel.client.lua  — Grok-tuned hit-stop, screen flash, FOV pulse, damage numbers
-- Listens to PrankRegistered events and plays satisfying feedback.
-- Place in: StarterPlayer > StarterPlayerScripts > CombatFeel (LocalScript)

local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local SoundService = game:GetService("SoundService")
local Workspace = game:GetService("Workspace")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Debris = game:GetService("Debris")

local Remotes = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))
local AssetIds = require(ReplicatedStorage.Modules:WaitForChild("AssetIds"))
local PrankConfig = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("PrankConfig"))

local player = Players.LocalPlayer
local playerGui = player:WaitForChild("PlayerGui")
local camera = Workspace.CurrentCamera

-- Combo tracking
local combo = 0
local lastComboTime = 0
local COMBO_TIMEOUT = 3  -- sec

local comboGui = Instance.new("ScreenGui")
comboGui.Name = "ComboGui"
comboGui.IgnoreGuiInset = false
comboGui.ResetOnSpawn = false
comboGui.Parent = playerGui

local comboLabel = Instance.new("TextLabel")
comboLabel.Size = UDim2.new(0, 320, 0, 80)
comboLabel.Position = UDim2.new(0.5, -160, 0.18, 0)
comboLabel.BackgroundTransparency = 1
comboLabel.Text = ""
comboLabel.Font = Enum.Font.GothamBlack
comboLabel.TextScaled = true
comboLabel.TextColor3 = Color3.fromRGB(255, 220, 50)
comboLabel.TextStrokeTransparency = 0
comboLabel.TextStrokeColor3 = Color3.fromRGB(0, 0, 0)
comboLabel.Visible = false
comboLabel.Parent = comboGui

-- Screen flash overlay
local flashGui = Instance.new("ScreenGui")
flashGui.Name = "ScreenFlash"
flashGui.IgnoreGuiInset = true
flashGui.ResetOnSpawn = false
flashGui.DisplayOrder = 60
flashGui.Parent = playerGui
local flash = Instance.new("Frame")
flash.Size = UDim2.fromScale(1, 1)
flash.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
flash.BackgroundTransparency = 1
flash.BorderSizePixel = 0
flash.Parent = flashGui

local function comboColorFor(c)
  if c >= 20 then return Color3.fromRGB(255, 100, 255) end  -- rainbow-ish
  if c >= 10 then return Color3.fromRGB(255, 80, 80) end    -- red
  if c >= 5  then return Color3.fromRGB(255, 165, 0) end    -- orange
  return Color3.fromRGB(255, 220, 50)                       -- yellow
end

local function bumpCombo()
  local now = os.clock()
  if (now - lastComboTime) < COMBO_TIMEOUT then
    combo = combo + 1
  else
    combo = 1
  end
  lastComboTime = now
  if combo >= 2 then
    comboLabel.Text = "x" .. combo .. " COMBO"
    comboLabel.TextColor3 = comboColorFor(combo)
    comboLabel.Visible = true
    -- Pulse
    comboLabel.Size = UDim2.new(0, 320, 0, 80)
    TweenService:Create(comboLabel, TweenInfo.new(0.2, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {Size = UDim2.new(0, 360, 0, 90)}):Play()
    task.delay(0.3, function()
      TweenService:Create(comboLabel, TweenInfo.new(0.15), {Size = UDim2.new(0, 320, 0, 80)}):Play()
    end)
    -- Auto fade
    task.delay(COMBO_TIMEOUT, function()
      if (os.clock() - lastComboTime) >= COMBO_TIMEOUT then
        TweenService:Create(comboLabel, TweenInfo.new(0.4), {TextTransparency = 1}):Play()
        task.wait(0.5)
        comboLabel.Visible = false
        comboLabel.TextTransparency = 0
        combo = 0
      end
    end)
  end
end

-- Use Tween.Completed instead of task.wait so we don't block the caller and
-- so subsequent pranks don't stack waits and stutter the camera.
local function hitStop(durationMS)
  local origFov = camera.FieldOfView
  local up = TweenService:Create(camera,
    TweenInfo.new((durationMS or 80) / 1000 * 0.4, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
    {FieldOfView = origFov + 8})
  up:Play()
  up.Completed:Once(function()
    TweenService:Create(camera,
      TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
      {FieldOfView = origFov}
    ):Play()
  end)
end

local function screenFlash(color, intensity)
  flash.BackgroundColor3 = color
  flash.BackgroundTransparency = 1 - intensity
  TweenService:Create(flash, TweenInfo.new(0.4, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1}):Play()
end

local function spawnDamageNumber(worldCFrame, amount)
  local part = Instance.new("Part")
  part.Anchored = true; part.CanCollide = false; part.Transparency = 1
  part.Size = Vector3.new(1, 1, 1)
  part.CFrame = worldCFrame + Vector3.new(math.random()*4-2, 4, math.random()*4-2)
  part.Parent = Workspace
  local g = Instance.new("BillboardGui")
  g.Size = UDim2.new(0, 200, 0, 80)
  g.AlwaysOnTop = true
  g.Parent = part
  local l = Instance.new("TextLabel")
  l.Size = UDim2.fromScale(1, 1)
  l.BackgroundTransparency = 1
  l.Text = "+" .. amount
  l.Font = Enum.Font.GothamBlack
  l.TextScaled = true
  l.TextColor3 = comboColorFor(combo)
  l.TextStrokeTransparency = 0
  l.TextStrokeColor3 = Color3.new(0, 0, 0)
  l.Parent = g
  task.spawn(function()
    for i = 1, 30 do
      part.CFrame = part.CFrame + Vector3.new(0, 0.18, 0)
      l.TextTransparency = i/30
      l.TextStrokeTransparency = i/30 * 0.7
      task.wait(0.04)
    end
    part:Destroy()
  end)
end

local function playPrankSound(prankName)
  local soundIdMap = {
    CatScratch  = AssetIds.cat_scratch,
    Pie         = AssetIds.pie_splat,
    Hairball    = AssetIds.fish_slap,
    Anvil       = AssetIds.anvil_clang,
    FartCloud   = AssetIds.tp_unroll,
    LaserEyes   = AssetIds.flight_whoosh,
    Whip        = AssetIds.cat_scratch,
    Purrgatory  = AssetIds.purrgatory,
  }
  local id = soundIdMap[prankName]
  if id and id ~= "rbxassetid://0" then
    local s = Instance.new("Sound")
    s.SoundId = id
    s.Volume = 1.0
    s.Parent = SoundService
    s:Play()
    Debris:AddItem(s, 4)
  end
end

if Remotes.PrankRegistered then
  Remotes.PrankRegistered.OnClientEvent:Connect(function(prankName, targetModel, chaos, fxPayload)
    local prank = PrankConfig.Pranks[prankName]
    bumpCombo()
    if prank and prank.screenShake and prank.screenShake > 0 then
      hitStop(80)
    end
    -- Screen flash color per prank
    local flashColor = Color3.fromRGB(255, 255, 200)
    if prankName == "Anvil" then flashColor = Color3.fromRGB(255, 200, 100)
    elseif prankName == "Pie" then flashColor = Color3.fromRGB(255, 240, 200)
    elseif prankName == "LaserEyes" then flashColor = Color3.fromRGB(255, 80, 80)
    elseif prankName == "Purrgatory" then flashColor = Color3.fromRGB(180, 80, 220)
    end
    screenFlash(flashColor, 0.35)
    -- Damage number
    if targetModel and targetModel.PrimaryPart and chaos and chaos > 0 then
      spawnDamageNumber(targetModel.PrimaryPart.CFrame, chaos)
    end
    -- Sound
    playPrankSound(prankName)
  end)
end

print("[CombatFeel] hit-stop, flash, combo, damage numbers, sounds wired")

]])

-- StarterPlayer/StarterPlayerScripts/DailyRewardPopup.client.lua
W({'StarterPlayer','StarterPlayerScripts','DailyRewardPopup'}, 'LocalScript', [[
-- DailyRewardPopup.client.lua
-- Shows the daily streak + claim button when the server announces availability
-- via DailyAvailable. (Old version polled leaderstats on a 5s timer; that was
-- racy and also only fired once even when not actually available.)
-- Place in: StarterPlayer > StarterPlayerScripts > DailyRewardPopup (LocalScript)

local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local Remotes = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))

local player = Players.LocalPlayer
local playerGui = player:WaitForChild("PlayerGui")

local DAY_REWARDS = {
  {day=1, label="500 Chaos"},
  {day=2, label="1.5K Chaos"},
  {day=3, label="3K Chaos + 1 Hell Token"},
  {day=4, label="5K Chaos"},
  {day=5, label="7.5K Chaos + 2 Hell Tokens"},
  {day=6, label="10K Chaos"},
  {day=7, label="25K Chaos + 5 Hell Tokens"},
}

local pulseLoops = {}  -- track pulse loops so we can stop them on close
local function stopPulses()
    for _, t in ipairs(pulseLoops) do
        pcall(function() t:Cancel() end)
    end
    pulseLoops = {}
end

local function showPopup(streakDay, serverReward)
    local existing = playerGui:FindFirstChild("DailyRewardPopup")
    if existing then existing:Destroy() end

    local popup = Instance.new("ScreenGui")
    popup.Name = "DailyRewardPopup"
    popup.IgnoreGuiInset = true
    popup.ResetOnSpawn = false
    popup.DisplayOrder = 80
    popup.Parent = playerGui

    local dim = Instance.new("Frame", popup)
    dim.Size = UDim2.fromScale(1, 1)
    dim.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
    dim.BackgroundTransparency = 0.5

    local card = Instance.new("Frame", popup)
    card.Size = UDim2.new(0, 480, 0, 380)
    card.AnchorPoint = Vector2.new(0.5, 0.5)
    card.Position = UDim2.new(0.5, 0, 0.5, 0)
    card.BackgroundColor3 = Color3.fromRGB(40, 20, 70)
    card.BorderSizePixel = 0
    Instance.new("UICorner", card).CornerRadius = UDim.new(0, 16)
    local cs = Instance.new("UIStroke", card); cs.Thickness = 3; cs.Color = Color3.fromRGB(255, 215, 0)

    local title = Instance.new("TextLabel", card)
    title.Size = UDim2.new(1, -40, 0, 40)
    title.Position = UDim2.new(0, 20, 0, 14)
    title.BackgroundTransparency = 1
    title.Text = "DAILY REWARD"
    title.Font = Enum.Font.GothamBlack
    title.TextScaled = true
    title.TextColor3 = Color3.fromRGB(255, 215, 0)

    local streakLabel = Instance.new("TextLabel", card)
    streakLabel.Size = UDim2.new(1, -40, 0, 30)
    streakLabel.Position = UDim2.new(0, 20, 0, 60)
    streakLabel.BackgroundTransparency = 1
    streakLabel.Text = "STREAK DAY " .. streakDay
    streakLabel.Font = Enum.Font.GothamBold
    streakLabel.TextScaled = true
    streakLabel.TextColor3 = Color3.fromRGB(255, 100, 100)

    local strip = Instance.new("Frame", card)
    strip.Size = UDim2.new(1, -40, 0, 90)
    strip.Position = UDim2.new(0, 20, 0, 100)
    strip.BackgroundTransparency = 1
    local layout = Instance.new("UIListLayout", strip)
    layout.FillDirection = Enum.FillDirection.Horizontal
    layout.HorizontalAlignment = Enum.HorizontalAlignment.Center
    layout.Padding = UDim.new(0, 4)

    for i = 1, 7 do
        local box = Instance.new("Frame", strip)
        box.Size = UDim2.new(0, 56, 0, 80)
        box.BackgroundColor3 = (i <= streakDay) and Color3.fromRGB(50, 200, 100) or Color3.fromRGB(60, 30, 90)
        box.BorderSizePixel = 0
        Instance.new("UICorner", box).CornerRadius = UDim.new(0, 8)
        if i == streakDay then
            local s = Instance.new("UIStroke", box); s.Thickness = 3; s.Color = Color3.fromRGB(255, 215, 0)
            local pulse = TweenService:Create(box,
                TweenInfo.new(0.6, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut, -1, true),
                {Size = UDim2.new(0, 60, 0, 84)})
            pulse:Play()
            table.insert(pulseLoops, pulse)
        end
        local dl = Instance.new("TextLabel", box)
        dl.Size = UDim2.fromScale(1, 0.4); dl.BackgroundTransparency = 1
        dl.Text = "D" .. i; dl.Font = Enum.Font.GothamBold; dl.TextScaled = true
        dl.TextColor3 = Color3.fromRGB(255, 255, 255)
        local rl = Instance.new("TextLabel", box)
        rl.Size = UDim2.fromScale(1, 0.6); rl.Position = UDim2.fromScale(0, 0.4); rl.BackgroundTransparency = 1
        local r = DAY_REWARDS[i]
        rl.Text = r and r.label:sub(1, 12) or ""
        rl.Font = Enum.Font.Gotham; rl.TextScaled = true
        rl.TextColor3 = Color3.fromRGB(255, 230, 200)
    end

    local rewardText = Instance.new("TextLabel", card)
    rewardText.Size = UDim2.new(1, -40, 0, 60)
    rewardText.Position = UDim2.new(0, 20, 0, 200)
    rewardText.BackgroundTransparency = 1
    rewardText.Text = "TODAY: " .. ((serverReward and serverReward.msg) or DAY_REWARDS[streakDay].label)
    rewardText.Font = Enum.Font.GothamBlack
    rewardText.TextScaled = true
    rewardText.TextColor3 = Color3.fromRGB(255, 230, 100)

    local claimBtn = Instance.new("TextButton", card)
    claimBtn.Size = UDim2.new(0, 280, 0, 60)
    claimBtn.Position = UDim2.new(0.5, -140, 0, 280)
    claimBtn.BackgroundColor3 = Color3.fromRGB(50, 200, 100)
    claimBtn.Text = "CLAIM"
    claimBtn.Font = Enum.Font.GothamBlack; claimBtn.TextScaled = true
    claimBtn.TextColor3 = Color3.fromRGB(255, 255, 255)
    Instance.new("UICorner", claimBtn).CornerRadius = UDim.new(0, 12)

    local function close()
        stopPulses()
        TweenService:Create(card, TweenInfo.new(0.4), {BackgroundTransparency = 1}):Play()
        TweenService:Create(dim, TweenInfo.new(0.4), {BackgroundTransparency = 1}):Play()
        task.wait(0.5)
        if popup then popup:Destroy() end
    end

    claimBtn.MouseButton1Click:Connect(function()
        claimBtn.Active = false
        if Remotes.RequestClaimDaily then
            task.spawn(function()
                pcall(function() Remotes.RequestClaimDaily:InvokeServer() end)
            end)
        end
        close()
    end)

    local x = Instance.new("TextButton", card)
    x.Size = UDim2.new(0, 36, 0, 36)
    x.Position = UDim2.new(1, -42, 0, 6)
    x.BackgroundTransparency = 1
    x.Text = "X"
    x.Font = Enum.Font.GothamBold; x.TextScaled = true
    x.TextColor3 = Color3.fromRGB(255, 200, 200)
    x.MouseButton1Click:Connect(close)
end

if Remotes.DailyAvailable then
    Remotes.DailyAvailable.OnClientEvent:Connect(function(streakDay, reward)
        showPopup(streakDay, reward)
    end)
end

]])

-- StarterPlayer/StarterPlayerScripts/EffectsController.client.lua
W({'StarterPlayer','StarterPlayerScripts','EffectsController'}, 'LocalScript', [[
-- EffectsController.client.lua
-- Plays prank visual + audio effects on PrankRegistered events.
-- Place in: StarterPlayer > StarterPlayerScripts > EffectsController (LocalScript)

local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local SoundService = game:GetService("SoundService")
local Workspace = game:GetService("Workspace")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local Debris = game:GetService("Debris")

local Remotes = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))
local PrankConfig = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("PrankConfig"))
local GameConfig = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("GameConfig"))

local player = Players.LocalPlayer
local camera = Workspace.CurrentCamera

local function shake(intensity)
    if intensity <= 0 then return end
    task.spawn(function()
        local steps = 10
        for i = 1, steps do
            local off = CFrame.new(
                (math.random()-0.5) * intensity * 0.1,
                (math.random()-0.5) * intensity * 0.1,
                0
            )
            camera.CFrame = camera.CFrame * off
            task.wait(0.02)
        end
    end)
end

local function spawnParticleBurst(cf, color, count)
    local emitterPart = Instance.new("Part")
    emitterPart.Anchored = true
    emitterPart.CanCollide = false
    emitterPart.Transparency = 1
    emitterPart.Size = Vector3.new(1,1,1)
    emitterPart.CFrame = cf
    emitterPart.Parent = Workspace

    local emitter = Instance.new("ParticleEmitter")
    emitter.Texture = "rbxasset://textures/particles/sparkles_main.dds"
    emitter.Color = ColorSequence.new(color)
    emitter.Lifetime = NumberRange.new(0.5, 1.0)
    emitter.Rate = 0
    emitter.Speed = NumberRange.new(8, 18)
    emitter.SpreadAngle = Vector2.new(180, 180)
    emitter.Size = NumberSequence.new(1.5, 0.2)
    emitter.Parent = emitterPart
    emitter:Emit(count)
    Debris:AddItem(emitterPart, 2)
end

local function playSound(soundId, parent, volume)
    if not soundId or soundId == "" or soundId == 0 or soundId == "rbxassetid://0" then return end
    local s = Instance.new("Sound")
    s.SoundId = tostring(soundId)
    s.Volume = math.clamp(volume or 1, 0, 1)
    s.Parent = parent or SoundService
    s:Play()
    Debris:AddItem(s, 5)
end

local function chaosFlyUp(amount, atCFrame)
    if amount <= 0 then return end
    local b = Instance.new("BillboardGui")
    b.Size = UDim2.new(0, 120, 0, 50)
    b.AlwaysOnTop = true
    b.StudsOffset = Vector3.new(0, 4, 0)
    -- attach to a temp part
    local p = Instance.new("Part")
    p.Anchored = true
    p.CanCollide = false
    p.Transparency = 1
    p.Size = Vector3.new(0.1,0.1,0.1)
    p.CFrame = atCFrame
    p.Parent = Workspace
    b.Parent = p

    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(1, 0, 1, 0)
    lbl.BackgroundTransparency = 1
    lbl.Text = "+" .. amount .. " 💚"
    lbl.TextColor3 = GameConfig.HUD_ACCENT_COLOR
    lbl.TextStrokeTransparency = 0
    lbl.Font = Enum.Font.GothamBlack
    lbl.TextScaled = true
    lbl.Parent = b

    local moveTween = TweenService:Create(p, TweenInfo.new(1.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {CFrame = atCFrame * CFrame.new(0, 6, 0)})
    local fadeTween = TweenService:Create(lbl, TweenInfo.new(1.2), {TextTransparency = 1, TextStrokeTransparency = 1})
    moveTween:Play(); fadeTween:Play()
    p.AncestryChanged:Connect(function()
        if not p.Parent then
            pcall(function() moveTween:Cancel() end)
            pcall(function() fadeTween:Cancel() end)
        end
    end)
    Debris:AddItem(p, 1.5)
end

-- ===== Prank effect dispatch =====
local function effectFor(prankName, cf, color)
    if prankName == "Pie" then
        spawnParticleBurst(cf, color, 35)
    elseif prankName == "Anvil" then
        -- Spawn a fake anvil that drops from sky
        local anvil = Instance.new("Part")
        anvil.Size = Vector3.new(4, 3, 3)
        anvil.Color = Color3.fromRGB(80, 80, 80)
        anvil.Material = Enum.Material.Metal
        anvil.Anchored = true
        anvil.CanCollide = false
        anvil.CFrame = cf * CFrame.new(0, 30, 0)
        anvil.Parent = Workspace
        TweenService:Create(anvil, TweenInfo.new(0.4, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {CFrame = cf * CFrame.new(0, 1.5, 0)}):Play()
        task.delay(0.4, function()
            spawnParticleBurst(cf, Color3.fromRGB(150, 150, 150), 50)
            Debris:AddItem(anvil, 1)
        end)
    elseif prankName == "FartCloud" then
        -- AOE green smoke
        local part = Instance.new("Part")
        part.Anchored = true
        part.CanCollide = false
        part.Size = Vector3.new(8, 4, 8)
        part.Material = Enum.Material.SmoothPlastic
        part.Color = Color3.fromRGB(140, 200, 80)
        part.Transparency = 0.4
        part.CFrame = cf
        part.Parent = Workspace
        TweenService:Create(part, TweenInfo.new(1.2), {Transparency = 1, Size = Vector3.new(16, 8, 16)}):Play()
        Debris:AddItem(part, 1.5)
        spawnParticleBurst(cf, color, 80)
    elseif prankName == "LaserEyes" then
        -- Beam from player char head to target
        local char = player.Character
        if char and char:FindFirstChild("Head") then
            local origin = char.Head.Position
            local target = cf.Position
            local mid = (origin + target) / 2
            local dist = (origin - target).Magnitude
            local beam = Instance.new("Part")
            beam.Anchored = true
            beam.CanCollide = false
            beam.Size = Vector3.new(0.5, 0.5, dist)
            beam.Color = Color3.fromRGB(255, 50, 50)
            beam.Material = Enum.Material.Neon
            beam.CFrame = CFrame.new(mid, target)
            beam.Parent = Workspace
            TweenService:Create(beam, TweenInfo.new(0.4), {Transparency = 1}):Play()
            Debris:AddItem(beam, 0.5)
        end
        spawnParticleBurst(cf, color, 60)
    end
end

Remotes.PrankRegistered.OnClientEvent:Connect(function(prankName, target, chaosGained, fxPayload)
    local prank = PrankConfig.getPrank(prankName)
    if not prank then return end
    local cf = fxPayload and fxPayload.targetCFrame or (target and target.PrimaryPart and target.PrimaryPart.CFrame) or CFrame.new()
    effectFor(prankName, cf, prank.particleColor)
    playSound(prank.soundId)
    if chaosGained and chaosGained > 0 then
        chaosFlyUp(chaosGained, cf)
        shake(prank.screenShake or 0)
    end
end)

return true

]])

