-- StarterPlayer/StarterPlayerScripts/GraphicsQuality.client.lua
W({'StarterPlayer','StarterPlayerScripts','GraphicsQuality'}, 'LocalScript', [[
-- GraphicsQuality.client.lua
-- Auto-detect mobile (TouchEnabled + no Mouse) and apply lower-quality
-- visuals: dimmer post-FX, fewer particles, reduced StreamingTargetRadius
-- (clientside hint only — the server is authoritative).
-- Player can override via settingsGraphicsQuality.

local Players = game:GetService("Players")
local UserInputService = game:GetService("UserInputService")
local Lighting = game:GetService("Lighting")
local Workspace = game:GetService("Workspace")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local Remotes = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))

local player = Players.LocalPlayer

local function applyPreset(quality)
    if quality == "low" then
        for _, fx in ipairs(Lighting:GetChildren()) do
            if fx:IsA("BloomEffect") then fx.Intensity = 1.2; fx.Size = 14 end
            if fx:IsA("DepthOfFieldEffect") then fx.Enabled = false end
            if fx:IsA("SunRaysEffect") then fx.Intensity = 0.05 end
        end
        local atm = Lighting:FindFirstChildOfClass("Atmosphere")
        if atm then atm.Density = 0.18 end
        Workspace.StreamingTargetRadius = math.min(Workspace.StreamingTargetRadius, 800)
    elseif quality == "medium" then
        for _, fx in ipairs(Lighting:GetChildren()) do
            if fx:IsA("BloomEffect") then fx.Intensity = 2.0; fx.Size = 20 end
            if fx:IsA("DepthOfFieldEffect") then fx.Enabled = true; fx.FarIntensity = 0.04 end
            if fx:IsA("SunRaysEffect") then fx.Intensity = 0.15 end
        end
        local atm = Lighting:FindFirstChildOfClass("Atmosphere")
        if atm then atm.Density = 0.24 end
    else  -- high
        for _, fx in ipairs(Lighting:GetChildren()) do
            if fx:IsA("BloomEffect") then fx.Intensity = 2.6; fx.Size = 24 end
            if fx:IsA("DepthOfFieldEffect") then fx.Enabled = true; fx.FarIntensity = 0.06 end
            if fx:IsA("SunRaysEffect") then fx.Intensity = 0.22 end
        end
    end
end

local function autoDetect()
    if UserInputService.TouchEnabled and not UserInputService.MouseEnabled then
        return "low"
    end
    -- Approximate desktop midrange detection: smaller workspaces or laptops
    if Workspace.CurrentCamera and Workspace.CurrentCamera.ViewportSize.X < 1366 then
        return "medium"
    end
    return "high"
end

-- Honor saved preference; otherwise use auto-detect
local applied = false
Remotes.UpdatePlayerData.OnClientEvent:Connect(function(d)
    if applied then return end
    applied = true
    local q = d.settingsGraphicsQuality
    if not q or q == "" then q = autoDetect() end
    applyPreset(q)
end)

-- Allow toggling at runtime via setting change
Remotes.UpdatePlayerData.OnClientEvent:Connect(function(d)
    if d.settingsGraphicsQuality then applyPreset(d.settingsGraphicsQuality) end
end)

]])

-- StarterPlayer/StarterPlayerScripts/HUDController.client.lua
W({'StarterPlayer','StarterPlayerScripts','HUDController'}, 'LocalScript', [[
-- HUDController.client.lua
-- Subscribes to player data updates and refreshes HUD state.
-- Place in: StarterPlayer > StarterPlayerScripts > HUDController (LocalScript)

local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local MarketplaceService = game:GetService("MarketplaceService")

local Remotes = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))
local GameConfig = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("GameConfig"))
local CosmeticConfig = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("CosmeticConfig"))

local player = Players.LocalPlayer
local playerGui = player:WaitForChild("PlayerGui")
local hud = playerGui:WaitForChild("MainHUD", 60)
if not hud then warn("[HUDController] No HUD found after 60s"); return end

local topBar = hud:WaitForChild("TopBar")
local chaosLabel = topBar:WaitForChild("ChaosLabel")
local levelContainer = topBar:WaitForChild("LevelContainer")
local levelLabel = levelContainer:WaitForChild("LevelLabel")
local xpFill = levelContainer:WaitForChild("XPBarBG"):WaitForChild("XPBarFill")
local rebirthLabel = topBar:WaitForChild("RebirthLabel")
local prankCol = hud:WaitForChild("PrankColumn")

local CurrentData = {}

local function formatNum(n)
    n = n or 0
    if n >= 1e9 then return string.format("%.2fB", n/1e9) end
    if n >= 1e6 then return string.format("%.2fM", n/1e6) end
    if n >= 1e3 then return string.format("%.1fK", n/1e3) end
    return tostring(math.floor(n))
end

local function showToast(message, color)
    local toast = hud:FindFirstChild("ToastFrame")
    if not toast then return end
    local lbl = Instance.new("TextLabel")
    lbl.Size = UDim2.new(1, 0, 1, 0)
    lbl.BackgroundTransparency = 0.2
    lbl.BackgroundColor3 = color or Color3.fromRGB(255, 100, 100)
    lbl.TextColor3 = Color3.new(0,0,0)
    lbl.TextScaled = true
    lbl.Font = Enum.Font.GothamBlack
    lbl.Text = message
    Instance.new("UICorner", lbl).CornerRadius = UDim.new(0, 12)
    lbl.Parent = toast
    task.delay(2.0, function()
        TweenService:Create(lbl, TweenInfo.new(0.5), {BackgroundTransparency = 1, TextTransparency = 1}):Play()
        task.wait(0.6)
        if lbl.Parent then lbl:Destroy() end
    end)
end

local function refresh()
    if not CurrentData then return end
    chaosLabel.Text = "💚 " .. formatNum(CurrentData.chaosPoints or 0)
    levelLabel.Text = "Level " .. (CurrentData.level or 1)
    rebirthLabel.Text = "👑 " .. (CurrentData.rebirths or 0)
    local lvl = CurrentData.level or 1
    local xpReq = GameConfig.xpRequired(lvl)
    local pct = math.clamp((CurrentData.xp or 0) / xpReq, 0, 1)
    TweenService:Create(xpFill, TweenInfo.new(0.3), {Size = UDim2.new(pct, 0, 1, 0)}):Play()
    for _, btn in ipairs(prankCol:GetChildren()) do
        if btn:IsA("TextButton") and btn:GetAttribute("PrankName") then
            local unlock = btn:GetAttribute("UnlockLevel")
            local locked = (CurrentData.level or 1) < unlock
            local overlay = btn:FindFirstChild("LockOverlay")
            if overlay then overlay.Visible = locked end
            btn:SetAttribute("Locked", locked)
        end
    end
end

Remotes.UpdatePlayerData.OnClientEvent:Connect(function(data) CurrentData = data; refresh() end)

Remotes.LevelUp.OnClientEvent:Connect(function(newLevel)
    showToast("LEVEL UP! " .. newLevel, GameConfig.HUD_ACCENT_COLOR)
end)

Remotes.NotifyClient.OnClientEvent:Connect(function(message, severity)
    local color = severity == "success" and GameConfig.HUD_ACCENT_COLOR or
                  severity == "warn" and Color3.fromRGB(255, 200, 0) or
                  Color3.fromRGB(255, 100, 100)
    showToast(message, color)
end)

if Remotes.ErrorNotify then
    Remotes.ErrorNotify.OnClientEvent:Connect(function(reason)
        showToast("Error: " .. tostring(reason), Color3.fromRGB(255, 100, 100))
    end)
end

Remotes.RebirthCompleted.OnClientEvent:Connect(function(newRebirths, newMult)
    showToast("REBIRTH! 👑 " .. newRebirths .. "  x" .. string.format("%.2f", newMult),
        Color3.fromRGB(255, 200, 0))
end)

Remotes.LeaderboardUpdated.OnClientEvent:Connect(function(top)
    local lbModal = hud:FindFirstChild("LeaderboardModal")
    if not lbModal then return end
    local list = lbModal:FindFirstChild("LBList")
    if not list then return end
    for _, c in ipairs(list:GetChildren()) do
        if c:IsA("TextLabel") then c:Destroy() end
    end
    for i, entry in ipairs(top) do
        local row = Instance.new("TextLabel")
        row.Size = UDim2.new(1, 0, 0, 32)
        row.BackgroundColor3 = i == 1 and Color3.fromRGB(255, 200, 0)
                              or i == 2 and Color3.fromRGB(180, 180, 180)
                              or i == 3 and Color3.fromRGB(180, 100, 50)
                              or Color3.fromRGB(40, 30, 60)
        row.TextColor3 = i <= 3 and Color3.new(0,0,0) or Color3.new(1,1,1)
        row.Font = Enum.Font.GothamBlack
        row.TextScaled = true
        row.LayoutOrder = i
        row.Text = string.format("%d. %s — %s", i, entry.name, formatNum(entry.chaos))
        Instance.new("UICorner", row).CornerRadius = UDim.new(0, 6)
        row.Parent = list
    end
end)

local function toggle(modalName)
    local m = hud:FindFirstChild(modalName)
    if m then m.Visible = not m.Visible end
end

-- Defined BEFORE button connections so the forward-reference bug is gone.
local function buildShopList(inventoryMode)
    local modal = hud:FindFirstChild("ShopModal")
    if not modal then return end
    local list = modal:FindFirstChild("ShopList")
    if not list then return end
    for _, c in ipairs(list:GetChildren()) do
        if c:IsA("Frame") or c:IsA("TextButton") then c:Destroy() end
    end
    -- Fire-and-forget preview event for SkinPreviewer
    local previewEv = playerGui:FindFirstChild("PreviewSkinEvent")
    for _, skinId in ipairs(CosmeticConfig.Order) do
        local skin = CosmeticConfig.Skins[skinId]
        local owned = CurrentData.ownedSkins and table.find(CurrentData.ownedSkins, skinId)
        if not (inventoryMode and not owned) then
            local row = Instance.new("Frame")
            row.Size = UDim2.new(1, -16, 0, 70)
            row.BackgroundColor3 = Color3.fromRGB(40, 25, 60)
            row.BorderSizePixel = 0
            Instance.new("UICorner", row).CornerRadius = UDim.new(0, 8)
            row.Parent = list

            -- Tap-anywhere-on-row preview button (under the labels, above the buy button).
            local previewClick = Instance.new("TextButton")
            previewClick.Size = UDim2.new(0.55, 0, 1, 0)
            previewClick.Position = UDim2.new(0, 0, 0, 0)
            previewClick.BackgroundTransparency = 1
            previewClick.Text = ""
            previewClick.Parent = row
            previewClick.MouseButton1Click:Connect(function()
                if previewEv then previewEv:Fire(skinId) end
            end)

            local nameLabel = Instance.new("TextLabel")
            nameLabel.Size = UDim2.new(0.4, 0, 0.5, 0)
            nameLabel.Position = UDim2.new(0.02, 0, 0, 0)
            nameLabel.BackgroundTransparency = 1
            nameLabel.Text = skin.displayName
            nameLabel.TextColor3 = Color3.new(1,1,1)
            nameLabel.Font = Enum.Font.GothamBlack
            nameLabel.TextScaled = true
            nameLabel.TextXAlignment = Enum.TextXAlignment.Left
            nameLabel.Parent = row

            local rarityLabel = Instance.new("TextLabel")
            rarityLabel.Size = UDim2.new(0.4, 0, 0.5, 0)
            rarityLabel.Position = UDim2.new(0.02, 0, 0.5, 0)
            rarityLabel.BackgroundTransparency = 1
            rarityLabel.Text = skin.rarity .. "  x" .. string.format("%.2f", skin.chaosMultiplier)
            rarityLabel.TextColor3 = skin.rarity == "Legendary" and Color3.fromRGB(255, 200, 0)
                                    or skin.rarity == "Epic" and Color3.fromRGB(200, 50, 255)
                                    or skin.rarity == "Rare" and Color3.fromRGB(80, 150, 255)
                                    or skin.rarity == "Mythic" and Color3.fromRGB(255, 80, 220)
                                    or Color3.fromRGB(180, 180, 180)
            rarityLabel.Font = Enum.Font.Gotham
            rarityLabel.TextScaled = true
            rarityLabel.TextXAlignment = Enum.TextXAlignment.Left
            rarityLabel.Parent = row

            local btn = Instance.new("TextButton")
            btn.Size = UDim2.new(0.35, 0, 0.8, 0)
            btn.Position = UDim2.new(0.6, 0, 0.1, 0)
            btn.Font = Enum.Font.GothamBlack
            btn.TextScaled = true
            btn.TextColor3 = Color3.new(1,1,1)
            btn.BorderSizePixel = 0
            Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 6)
            btn.Parent = row

            if owned then
                if CurrentData.equippedSkin == skinId then
                    btn.Text = "EQUIPPED"
                    btn.BackgroundColor3 = Color3.fromRGB(0, 150, 0)
                else
                    btn.Text = "EQUIP"
                    btn.BackgroundColor3 = Color3.fromRGB(0, 200, 100)
                    btn.MouseButton1Click:Connect(function()
                        Remotes.RequestEquipSkin:InvokeServer(skinId)
                    end)
                end
            else
                if skin.currency == "chaos" then
                    btn.Text = "💚 " .. formatNum(skin.cost)
                    btn.BackgroundColor3 = Color3.fromRGB(0, 200, 100)
                    btn.MouseButton1Click:Connect(function()
                        local ok, err = Remotes.RequestPurchaseSkinChaos:InvokeServer(skinId)
                        if not ok then showToast("Purchase failed: " .. tostring(err)) end
                    end)
                elseif skin.currency == "helltokens" then
                    btn.Text = "🔥 " .. formatNum(skin.cost)
                    btn.BackgroundColor3 = Color3.fromRGB(200, 80, 0)
                    btn.MouseButton1Click:Connect(function()
                        local ok, err = Remotes.RequestPurchaseSkinHellTokens:InvokeServer(skinId)
                        if not ok then showToast("Purchase failed: " .. tostring(err)) end
                    end)
                else
                    -- Robux currency. If GamePass ID hasn't been filled in,
                    -- show "Coming Soon" instead of a dead-end ROBUX button.
                    local gpKey = skin.gamepassKey or (string.upper(skinId) .. "_SKIN")
                    local gpId = GameConfig.GAMEPASS_IDS[gpKey]
                    if gpId and gpId ~= 0 then
                        btn.Text = "ROBUX"
                        btn.BackgroundColor3 = Color3.fromRGB(0, 150, 255)
                        btn.MouseButton1Click:Connect(function()
                            MarketplaceService:PromptGamePassPurchase(player, gpId)
                        end)
                    else
                        btn.Text = "SOON"
                        btn.BackgroundColor3 = Color3.fromRGB(80, 80, 100)
                        btn.AutoButtonColor = false
                    end
                end
            end
        end
    end
end

local botBar = hud:FindFirstChild("BottomBar")
if botBar then
    local shopBtn = botBar:FindFirstChild("ShopButton")
    local invBtn = botBar:FindFirstChild("InventoryButton")
    local rebirthBtn = botBar:FindFirstChild("RebirthButton")
    local lbBtn = botBar:FindFirstChild("LeaderboardButton")

    if shopBtn then shopBtn.MouseButton1Click:Connect(function() toggle("ShopModal"); buildShopList() end) end
    if invBtn then invBtn.MouseButton1Click:Connect(function() toggle("ShopModal"); buildShopList(true) end) end
    if rebirthBtn then
        rebirthBtn.MouseButton1Click:Connect(function()
            local ok, result = Remotes.RequestRebirth:InvokeServer()
            if not ok then
                local msg = "Cannot rebirth: " .. tostring(result)
                showToast(msg, Color3.fromRGB(255, 100, 100))
            end
        end)
    end
    if lbBtn then lbBtn.MouseButton1Click:Connect(function() toggle("LeaderboardModal") end) end
end

for _, m in ipairs({hud:FindFirstChild("ShopModal"), hud:FindFirstChild("LeaderboardModal")}) do
    if m then
        local close = m:FindFirstChild("CloseButton")
        if close then close.MouseButton1Click:Connect(function() m.Visible = false end) end
    end
end

return true

]])

-- StarterPlayer/StarterPlayerScripts/InputHandler.client.lua
W({'StarterPlayer','StarterPlayerScripts','InputHandler'}, 'LocalScript', [[
-- InputHandler.client.lua
-- Wires HUD buttons (Summon, Pranks) to RemoteEvents. Also handles auto-target finding.
-- Place in: StarterPlayer > StarterPlayerScripts > InputHandler (LocalScript)

local Players = game:GetService("Players")
local Workspace = game:GetService("Workspace")
local UserInputService = game:GetService("UserInputService")
local TweenService = game:GetService("TweenService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local Remotes = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))
local PrankConfig = require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("PrankConfig"))

local player = Players.LocalPlayer
local playerGui = player:WaitForChild("PlayerGui")
local hud = playerGui:WaitForChild("MainHUD", 60)
if not hud then
    -- Surface failure visibly instead of silently disabling all input.
    local fallback = Instance.new("ScreenGui", playerGui)
    fallback.Name = "InputHandlerError"
    local lbl = Instance.new("TextLabel", fallback)
    lbl.Size = UDim2.new(0, 320, 0, 60)
    lbl.Position = UDim2.new(0.5, -160, 0, 20)
    lbl.BackgroundColor3 = Color3.fromRGB(80, 0, 0)
    lbl.TextColor3 = Color3.fromRGB(255, 200, 200)
    lbl.Text = "HUD failed to load. Rejoin."
    lbl.Font = Enum.Font.GothamBlack
    lbl.TextScaled = true
    return
end

local summonBtn = hud:WaitForChild("SummonButton")
local prankCol = hud:WaitForChild("PrankColumn")

local function nearestNPC(maxRange)
    local char = player.Character
    if not char then return nil end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    if not hrp then return nil end
    local closest, dist = nil, math.huge
    -- Search BOTH summoned NPCs and ambient pedestrians.
    for _, folderName in ipairs({"PrankNPCs", "AmbientCrowd"}) do
        local folder = Workspace:FindFirstChild(folderName)
        if folder then
            for _, m in ipairs(folder:GetChildren()) do
                if m:IsA("Model") and m:GetAttribute("KittyRaiserNPC") and not m:GetAttribute("Pranked") then
                    local p = m.PrimaryPart or m:FindFirstChild("HumanoidRootPart")
                    if p then
                        local d = (p.Position - hrp.Position).Magnitude
                        if d < dist and d <= maxRange then
                            dist = d; closest = m
                        end
                    end
                end
            end
        end
    end
    return closest
end

local function pop(btn)
    local origSize = btn.Size
    local big = UDim2.new(origSize.X.Scale, origSize.X.Offset + 8, origSize.Y.Scale, origSize.Y.Offset + 8)
    TweenService:Create(btn, TweenInfo.new(0.08), {Size = big}):Play()
    task.delay(0.08, function()
        TweenService:Create(btn, TweenInfo.new(0.1), {Size = origSize}):Play()
    end)
end

summonBtn.MouseButton1Click:Connect(function()
    pop(summonBtn)
    Remotes.RequestSummonHuman:FireServer()
end)

local prankBtnCooldowns = {}
local function tryPrank(prankName, btn)
    if not btn or btn:GetAttribute("Locked") then return end
    if prankBtnCooldowns[prankName] and os.clock() < prankBtnCooldowns[prankName] then return end
    local prank = PrankConfig.Pranks[prankName]
    if not prank then return end
    local npc = nearestNPC(prank.rangeStuds)
    if not npc then return end
    pop(btn)
    Remotes.RequestPrank:FireServer(prankName, npc)
    prankBtnCooldowns[prankName] = os.clock() + prank.cooldown
    local cdOverlay = btn:FindFirstChild("CooldownOverlay")
    if cdOverlay then
        cdOverlay.Visible = true
        cdOverlay.Size = UDim2.new(1, 0, 1, 0)
        local tween = TweenService:Create(cdOverlay,
            TweenInfo.new(prank.cooldown, Enum.EasingStyle.Linear),
            {Size = UDim2.new(1, 0, 0, 0)})
        tween:Play()
        tween.Completed:Connect(function() cdOverlay.Visible = false end)
    end
end

for _, btn in ipairs(prankCol:GetChildren()) do
    if btn:IsA("TextButton") and btn:GetAttribute("PrankName") then
        local prankName = btn:GetAttribute("PrankName")
        btn.MouseButton1Click:Connect(function() tryPrank(prankName, btn) end)
    end
end

-- Keyboard shortcuts. Skip if player is typing in chat (gp = true means
-- another GUI consumed the input).
local KEY_TO_PRANK = {
    [Enum.KeyCode.One]   = "Pie",
    [Enum.KeyCode.Two]   = "Anvil",
    [Enum.KeyCode.Three] = "FartCloud",
    [Enum.KeyCode.Four]  = "LaserEyes",
}
UserInputService.InputBegan:Connect(function(input, gp)
    if gp then return end
    if input.KeyCode == Enum.KeyCode.E then
        Remotes.RequestSummonHuman:FireServer()
        return
    end
    local prankName = KEY_TO_PRANK[input.KeyCode]
    if prankName then
        local btn = prankCol:FindFirstChild("Prank_" .. prankName)
        tryPrank(prankName, btn)
    end
end)

return true

]])

