Remotes.UpdatePlayerData.OnClientEvent:Connect(function(d)
    if subscribed then return end
    subscribed = true
    if not d.seenIntro then
        showIntro()
        Remotes.RequestSettingChange:InvokeServer("seenIntro", true)
    end
end)

